={{ (function() {
  const paramsString = $fromAI('Tool_Parameters');

  // Default path
  const defaultParams = {
    path: "/home/user/documents"
  };

  if (!paramsString) {
    return defaultParams;
  }

  try {
    // ลองแปลง JSON ก่อน
    const params = JSON.parse(paramsString);
    return {
      path: params.path || defaultParams.path
    };
  } catch (e) {
    // ถ้าแปลง JSON ไม่ได้ ถือว่าเป็น path string โดยตรง
    if (typeof paramsString === 'string' && paramsString.trim().length > 0) {
      return {
        path: paramsString.trim()
      };
    }
    return defaultParams;
  }
})() }}

={{ (function() {
  const paramsString = $fromAI('Tool_Parameters');

  // Default parameters
  const defaultParams = {
    query: "search term",
    limit: 10
  };

  if (!paramsString) {
    return defaultParams;
  }

  try {
    // ลองแปลง JSON ก่อน
    const params = JSON.parse(paramsString);
    return {
      query: params.query || params.search || params.keyword || defaultParams.query,
      limit: params.limit || params.max || params.count || defaultParams.limit
    };
  } catch (e) {
    // ถ้าแปลง JSON ไม่ได้ ถือว่าเป็น search string โดยตรง
    if (typeof paramsString === 'string' && paramsString.trim().length > 0) {
      return {
        query: paramsString.trim(),
        limit: defaultParams.limit
      };
    }
    return defaultParams;
  }
})() }}
